import React from 'react'
import { colors, IconButton } from '@fs/zion-ui'
import { ContentCompose } from '@fs/zion-icon'
import { useHistory, useRouteMatch } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import { useChatState } from '../providers/ChatStateProvider'
import useChatLog from '../hooks/useChatLog'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'

const EditIcon = () => <ContentCompose color={colors.color70} />

export default function ChatWindowHeaderActions() {
  const [t] = useTranslation()
  const { createChatRecipientChipCollection, restrictToManagedGroups } = useChatState()
  const history = useHistory()
  const isHelperRoute = useRouteMatch('/chat-window/helper')
  const createTooltip = t('chat.create-private-chat.action', 'Create Private Chat')
  const { resetChips } = createChatRecipientChipCollection
  const { track } = useChatLog({ component: '[ChatWindowHeaderActions]' })

  const onClick = () => {
    resetChips()
    track({ link_name: `Chat:Click Create Chat: fs_direct` })
    history.push(buildChatRoute(CHAT_ROUTE_KEY.CREATE_EMPTY_DIRECT_CHAT))
  }

  return isHelperRoute || restrictToManagedGroups ? null : (
    <IconButton data-testid="create-direct-chat" title={createTooltip} Icon={EditIcon} onClick={onClick} />
  )
}
