import React from 'react'
import { useTranslation, Trans } from 'react-i18next'
import { i18n } from '@fs/zion-locale'
import { Paragraph, Button, DialogOverlay, DialogOverlayActions, Separator } from '@fs/zion-ui'
import { Link } from '@fs/zion-router'

const communityLocales = new Set(['en', 'es', 'fr', 'pt', 'de', 'it', 'ja', 'zh', 'ko'])

const Footer = ({ communityLink, ...overlay }): JSX.Element => {
  const [t] = useTranslation()
  const cancelText = t('common-ui:cancel.action', 'Cancel')
  const closeText = t('common-ui:close.action', 'Close')
  return (
    <DialogOverlayActions>
      <Button
        data-testid="usabilla-fallback-cancel"
        onClick={overlay.handleClick}
        emphasis={communityLink ? 'medium' : 'high'}
      >
        {communityLink ? cancelText : closeText}
      </Button>
      {communityLink && (
        <Button
          data-testid="usabilla-fallback-continue"
          emphasis="high"
          to={communityLink}
          external
          target="_blank"
          onClick={overlay.handleClick}
        >
          {t('common-ui:continue.action')}
        </Button>
      )}
    </DialogOverlayActions>
  )
}

const FallbackOverlay = ({ communityLink, ...overlay }): JSX.Element => {
  const [t] = useTranslation()
  const showCommunity = communityLocales.has(i18n.language)
  return (
    <DialogOverlay
      {...overlay}
      title={t('common-ui:feedback.label', 'Feedback')}
      data-testid="usabilla-fallback-overlay"
      footer={<Footer communityLink={showCommunity ? communityLink : undefined} {...overlay} />}
    >
      <Paragraph size="sm">
        {t(
          'usabilla.fallback.error',
          'We couldn’t complete that action. A popup blocker might be getting in the way. Try turning off your browser’s popup blocker for this site, then try again.'
        )}
        &nbsp;
        {showCommunity && (
          <Trans
            i18nKey="usabilla.fallback.visit-community"
            defaults="If you still need help or want to report an issue, please visit the <0>FamilySearch Community</0> and share your comment there."
          >
            <Link external target="_blank" onClick={overlay.handleClick} to={communityLink} noPrependLocaleCode />
          </Trans>
        )}
      </Paragraph>
      <Separator />
    </DialogOverlay>
  )
}

export default FallbackOverlay
