import React from 'react'
import { Row } from '@fs/zion-ui'
import { VisuallyHidden } from '@reach/visually-hidden'
import { useTranslation } from 'react-i18next'
import ChatWindowHeaderActions from './ChatWindowHeaderActions'
import ChatWindowHeaderTypes from './ChatWindowHeaderTypes'
import ChatHeaderMenu from '../chat-header/ChatHeaderMenu'
import { useChatState } from '../providers/ChatStateProvider'

export default function ChatWindowHeader() {
  const [t] = useTranslation()
  const { connectError } = useChatState()
  if (connectError) return null
  return (
    <>
      <VisuallyHidden as="h2">{t('chat.label', 'Chat')}</VisuallyHidden>
      <Row alignY="middle">
        <ChatWindowHeaderTypes growX />
        <ChatWindowHeaderActions />
        <ChatHeaderMenu />
      </Row>
    </>
  )
}
