import React, { useContext } from 'react'
import { useTranslation } from 'react-i18next'
import { useHistory, useRouteMatch } from '@fs/zion-router'
import { Bleed, Tab, Tabs, H1, Row, Paragraph } from '@fs/zion-ui'
import { css } from '@linaria/core'
import { useChatState } from '../providers/ChatStateProvider'
import { getUnreadChatsTotalCount } from '../helpers/stream/streamChatHelper'
import useChatLog from '../hooks/useChatLog'
import { helperContext } from '../chat-helper-tab/HelperProvider'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'

const pathMap = {
  0: 'chats',
  1: 'helper',
}

const headerCss = css`
  font-weight: bold;
  overflow: hidden;
  font-size: 18px;
  white-space: nowrap;
`

export default function ChatWindowHeaderTypes() {
  const helperContextValue = useContext(helperContext)
  const { channels, threadList } = useChatState()
  const unreadChatsCount = getUnreadChatsTotalCount({ channels })
  const unreadThreadsCount = threadList?.filter((thread) => thread?.ownUnreadCount > 0).length || 0
  const totalUnreadCount = unreadChatsCount + unreadThreadsCount
  const unreadCountLabel = totalUnreadCount > 0 ? totalUnreadCount : null

  const hasHelperContext = helperContextValue && helperContextValue.myStatus !== undefined

  if (hasHelperContext) {
    return <ChatWindowHeaderTabs helperContextValue={helperContextValue} unreadCountLabel={unreadCountLabel} />
  }
  return <ChatWindowHeaderText unreadCountLabel={unreadCountLabel} />
}

function ChatWindowHeaderText({ unreadCountLabel }) {
  const [t] = useTranslation()

  return (
    <Row gutters="xxs" guttersY="none" as="span" ChildWrapper="span" data-testid="chats-tab">
      <div className={headerCss}>
        <H1 size="H5">{t('chat.chats.action', 'Chats')}</H1>
      </div>

      {unreadCountLabel && (
        <Paragraph as="span" secondary noShrinkX size="xs">
          ({unreadCountLabel})
        </Paragraph>
      )}
    </Row>
  )
}
function ChatWindowHeaderTabs({ helperContextValue, unreadCountLabel }) {
  const [t] = useTranslation()
  const history = useHistory()
  const { track } = useChatLog({ component: '[ChatWindowHeaderActions]' })
  const isHelperRoute = useRouteMatch('/chat-window/helper')
  const { discussions, myStatus } = helperContextValue
  const { languages } = myStatus || {}
  const langs = languages?.split(',').map((lang) => lang.trim())
  const helpeesWaitingCount = langs?.reduce((count, lang) => {
    return count + Number(discussions?.[lang]?.count || 0)
  }, 0)

  const onTabClick = (selectedIndex) => {
    track({ link_name: `Chat:Click ${pathMap[selectedIndex]} Tab` })
    switch (selectedIndex) {
      case 0:
        if (isHelperRoute) {
          if (history.length > 1) {
            history.goBack()
          } else {
            history.push(buildChatRoute(CHAT_ROUTE_KEY.CHATS))
          }
        }
        break
      case 1:
        if (!isHelperRoute) {
          history.push(buildChatRoute(CHAT_ROUTE_KEY.HELPER))
        }
        break
      default:
        break
    }
  }
  const tabIndex = isHelperRoute ? 1 : 0
  return (
    <Bleed top>
      <Tabs defaultIndex={tabIndex} index={tabIndex} onChange={onTabClick}>
        <Tab data-testid="chats-tab" title={t('chat.chats.action', 'Chats')} count={unreadCountLabel} />
        <Tab data-testid="helper-tab" title="Helper" count={helpeesWaitingCount} />
      </Tabs>
    </Bleed>
  )
}
